import { writeFile } from "node:fs/promises";

const API_BASE = process.env.NEXT_PUBLIC_API_BASE_URL ?? "http://127.0.0.1:8000";
const OPENAPI_URL = `${API_BASE}/openapi.json`;
const TARGET_FILE = "lib/generated/api-types.ts";

function buildTypes() {
  return `/* eslint-disable */
/* Auto-generated by scripts/generate-api-types.mjs */

export type JobStatus =
  | "queued"
  | "running"
  | "done"
  | "failed"
  | "timeout"
  | "invalid_repo";

export type ProgressStage = "ingest" | "classify" | "detect" | "graph" | "narrate";

export interface AnalysisJob {
  job_id: string;
  status: JobStatus;
  created_at: string;
  updated_at: string;
  progress_stage?: ProgressStage;
  message?: string;
}

export interface EvidenceRef {
  commit_sha: string;
  file_paths?: string[];
  reason: string;
}

export interface DecisionMoment {
  decision_id: string;
  type: "convergence" | "replacement" | "unblocking" | "correction" | "architectural_pivot";
  title: string;
  summary: string;
  contributor_id: string;
  timestamp: string;
  confidence: number;
  evidence: EvidenceRef[];
}

export interface GraphNode {
  id: string;
  kind: "contributor" | "decision";
  label: string;
  influence_score: number;
}

export interface GraphEdge {
  id: string;
  source: string;
  target: string;
  weight: number;
  relation: "builds_on" | "unblocks" | "corrects";
}

export interface ContributorProfile {
  contributor_id: string;
  name: string;
  role: "Initiator" | "Implementer" | "Corrector" | "Unblocker";
  narrative: string;
  confidence: number;
  top_decisions: string[];
  evidence: Array<{ commit_sha: string; reason: string }>;
}

export interface AnalysisResult {
  job_id: string;
  project: {
    name: string;
    repo_url: string;
    commit_count: number;
    contributors_count: number;
  };
  decisions: DecisionMoment[];
  graph: {
    nodes: GraphNode[];
    edges: GraphEdge[];
  };
  contributors: ContributorProfile[];
  warnings: string[];
}
`;
}

async function main() {
  const response = await fetch(OPENAPI_URL);
  if (!response.ok) {
    throw new Error(`Failed to fetch OpenAPI: ${response.status} ${response.statusText}`);
  }
  await response.json();
  await writeFile(TARGET_FILE, buildTypes(), "utf8");
  console.log(`Generated ${TARGET_FILE} from ${OPENAPI_URL}`);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
